import json

with open('/root/books/webapp/books.json', encoding='utf-8') as f:
    books = json.load(f)

fixes = {
    867: {
        "Советская Армения и независимость": "В 1920 году Армения была советизирована и вошла в СССР. Советский период принёс индустриализацию и образование — и одновременно репрессии и подавление культуры. В 1988 году землетрясение унесло около двадцати пяти тысяч жизней — оно совпало с нарастанием движения за независимость. В 1991 году Армения провозгласила независимость после распада СССР. Сразу началась война с Азербайджаном за Нагорный Карабах. Война, экономический коллапс, энергетическая блокада — первые годы независимости были тяжелейшими. Потом последовало медленное восстановление. Армения сегодня — маленькое государство в сложном геополитическом окружении ищущее своё место в мире.",
    },
    869: {
        "Саргон — первый в истории имперский завоеватель": "Саргон Аккадский — первый строитель настоящей территориальной империи. Около 2334 года до нашей эры он захватил власть в Кише и начал завоевания. За несколько десятилетий подчинил все города Шумера а потом — Сирию и часть Анатолии. Его держава простиралась от Персидского залива до Средиземного моря. Это была не просто победа одного города над другим — это создание принципиально новой конструкции: единого государства управляемого через назначенных чиновников. До Саргона мир знал только города-государства. После него стали возможны империи. Он не просто создал государство — он создал саму идею империи которую человечество воспроизводит до наших дней.",
    },
    870: {
        "Вавилон — вечный город": "Вавилон стал символом великого города ещё в библейские времена. Вавилонская башня — зиккурат Этеменанки высотой около девяноста метров — поражала воображение всего Ближнего Востока. Навуходоносор II в VI веке до нашей эры отстроил Вавилон заново сделав его крупнейшим городом мира. Ворота Иштар из синих глазурованных кирпичей реконструированы в Берлинском Пергамском музее. Вавилонская цивилизация дала астрономию предсказывавшую затмения, шестидесятеричную математику и великую литературу. Когда Кир Великий взял Вавилон в 539 году его солдаты были поражены увиденным — ничего подобного в известном им мире не существовало.",
        "Ирригация и сельское хозяйство": "Основой месопотамской цивилизации была ирригация — сеть каналов для орошения полей. Тигр и Евфрат разливаются весной — слишком поздно для посева и рано для урожая. Нужно было запасать воду. Создание и поддержание каналов требовало тысяч людей — государство возникло именно как ирригационная администрация. Месопотамские поля давали урожай зерна поражавший современников — тридцатикратный сбор при посеве. Именно здесь одомашнили пшеницу и ячмень — культуры кормящие человечество до сих пор. Ирригация была революцией сравнимой с индустриальной — она позволила кормить города и освободить людей от земледелия для других занятий.",
        "Миф о Потопе": "Шумерский миф о Потопе — праобраз библейской истории Ноя — возник из реального опыта. Геологи нашли слои ила в раскопках Ура свидетельствующие о катастрофических наводнениях около 2900 года до нашей эры. Разлив Тигра и Евфрата затопил всю обитаемую долину создав впечатление что весь мир покрыт водой. Этот опыт закодировался в мифе. Шумерский Зиусудра, аккадский Утнапиштим, библейский Ной — герои одного нарратива. Когда в 1872 году прочли аккадскую версию Потопа на табличках это был скандал — история Ноя имела предшественника на тысячу лет старше. Месопотамия снова перевернула представления о происхождении нашей культуры.",
    }
}

for book in books:
    if book['id'] in fixes:
        for thought in book.get('thoughts', []):
            if thought['title'] in fixes[book['id']]:
                thought['example'] = fixes[book['id']][thought['title']]

with open('/root/books/webapp/books.json', 'w', encoding='utf-8') as f:
    json.dump(books, f, ensure_ascii=False, separators=(',', ':'))

errors = []
for book in books:
    if book['id'] in [867, 868, 869, 870]:
        for t in book.get('thoughts', []):
            total = len(t['title']) + len(t['example'])
            if not (600 <= total <= 800):
                errors.append(f"{book['id']} / {t['title']}: {total}")

print(f"Ошибок: {len(errors)}")
for e in errors:
    print(' ', e)
print("Done!")
